$since=(Get-Date).AddDays(-3);$dir="$env:USERPROFILE\Desktop";$base="power_audit_last3d";$tmp=Join-Path $dir "$base.tmp.txt";$ids=41,6008,1074,1076,12,13,6005,6006,6009,1001,42,1,104;Get-WinEvent -FilterHashtable @{LogName='System';StartTime=$since;Id=$ids} -ErrorAction SilentlyContinue|Sort-Object TimeCreated|ForEach-Object{("{0:u} Id={1} Provider={2}n{3}n---n" -f $_.TimeCreated,$_.Id,$_.ProviderName,($_.Message -replace "r",""))}|Out-File -Encoding UTF8 $tmp;$now=Get-Date;$boot=(Get-CimInstance Win32_OperatingSystem).LastBootUpTime;Add-Content -Encoding UTF8 $tmp ("n=== BOOT ===nLastBootUpTime: {0:u}nSystemUptime: {1}n" -f $boot,($now-$boot));Add-Content -Encoding UTF8 $tmp "=== PROCESS UPTIME (winlogon/explorer/java) ===";Get-Process winlogon,explorer,java -ErrorAction SilentlyContinue|ForEach-Object{try{$st=$_.StartTime}catch{$st=$null};[pscustomobject]@{Name=$_.Name;Id=$_.Id;StartTime=$st;Uptime=($(if($st){$now-$st}else{$null}))}}|Sort-Object Name,Id|Format-Table -AutoSize|Out-String|Add-Content -Encoding UTF8 $tmp;$h=(Get-FileHash -Algorithm SHA256 $tmp).Hash;$final=Join-Path $dir ("{0}_{1}.txt" -f $base,$h.Substring(0,12));Move-Item -Force $tmp $final;$final